import numpy as np

class _ArrayStr(str):
    def __new__(cls, array):
        self = str.__new__(cls, repr(array))
        self._array = array
        return self
    @property
    def shape(self):
        return self._array.shape
    @property
    def flags(self):
        return self._array.flags

def kln_to_kn(kln, N_k, cleanup=False):
    K, L, N_max = np.shape(kln)
    N = np.sum(N_k)
    kn = np.zeros((L, N), dtype=np.float64)
    i = 0
    for k in range(K):
        for ik in range(int(N_k[k])):
            kn[:, i] = kln[k, :, ik]
            i += 1
    if cleanup:
        del kln
    return _ArrayStr(kn)

